module top_module(
  input a,
  input b,
  input c,
  input d,
  output out
);wire and_result, cd, not_cd;

  // AND gate for a and b
  assign and_result = a & b;

  // OR gate for c and d
  assign cd = c | d;

  // NOT gate for cd
  assign not_cd = ~cd;

  // AND gate for and_result and not_cd
  assign out = and_result & not_cd;

endmodule
